def parse_user_input(prompt: str, input_type: str = "list") -> list:
    """Parse user input for keys and arguments."""
    raw = input(prompt).strip()
    if not raw:
        return []
    if input_type == "list":
        # Accept comma-separated values
        return [item.strip() for item in raw.split(",") if item.strip()]
    return raw


