def main():
    """Main entry point."""
    import argparse

    parser = argparse.ArgumentParser(description="Redis Lua Script Executor")
    parser.add_argument("--host", default="localhost", help="Redis host (default: localhost)")
    parser.add_argument("--port", type=int, default=6379, help="Redis port (default: 6379)")
    parser.add_argument("--db", type=int, default=0, help="Redis database (default: 0)")
    parser.add_argument("--password", default=None, help="Redis password")
    parser.add_argument("--mode", choices=["interactive", "demo", "execute"],
                        default="interactive", help="Run mode")
    parser.add_argument("--script", default=None, help="Lua script to execute (for execute mode)")
    parser.add_argument("--keys", default="", help="Comma-separated keys (for execute mode)")
    parser.add_argument("--args", default="", help="Comma-separated args (for execute mode)")

    args = parser.parse_args()

    try:
        client = RedisLuaClient(
            host=args.host,
            port=args.port,
            db=args.db,
            password=args.password
        )
    except redis.ConnectionError:
        print("Could not connect to Redis. Please check your connection settings.")
        sys.exit(1)

    if args.mode == "demo":
        demo_mode(client)

    elif args.mode == "execute":
        if not args.script:
            print("Error: --script is required in execute mode")
            sys.exit(1)
        keys = [k.strip() for k in args.keys.split(",") if k.strip()] if args.keys else []
        script_args = [a.strip() for a in args.args.split(",") if a.strip()] if args.args else []
        result = client.execute_lua_script(args.script, keys, script_args)
        print(json.dumps({"result": result}, default=str))

    else:
        interactive_mode(client)


if __name__ == "__main__":
    main()